UPDATE articles SET content = '[{"id":"e1","type":"paragraph","text":"Данный металл можно добыть в виде руды в **Виртуальных карьерах**, или при добыче **камня**, **серы** или **металла**."},{"id":"e2","type":"divider"},{"id":"e3","type":"paragraph","text":"При переплавке руды на выходе получается **Медный слиток**, а при переработке в переработчике — **медная пыль**."},{"id":"e4","type":"tip","icon":"Применение","text":"Используется в кастомном крафте в виде **слитков** или **пыли**."}]' WHERE id = 12;

UPDATE articles SET content = '[{"id":"f1","type":"paragraph","text":"Данный металл можно добыть в виде руды в **Виртуальных карьерах**, или при добыче **металла**."},{"id":"f2","type":"divider"},{"id":"f3","type":"paragraph","text":"При переплавке руды на выходе получается **Серебряный слиток**, а при переработке в переработчике — **серебряная пыль**."},{"id":"f4","type":"tip","icon":"Применение","text":"Используется в кастомном крафте в виде **слитков** или **пыли**."}]' WHERE id = 13;

UPDATE articles SET content = '[{"id":"g1","type":"paragraph","text":"Данный металл можно добыть в виде руды в **Виртуальных карьерах**, или при добыче **серы**."},{"id":"g2","type":"divider"},{"id":"g3","type":"paragraph","text":"При переплавке руды на выходе получается **Золотой слиток**, а при переработке в переработчике — **золотая пыль**."},{"id":"g4","type":"tip","icon":"Применение","text":"Используется в кастомном крафте в виде **слитков** или **пыли**."}]' WHERE id = 14;

UPDATE articles SET content = '[{"id":"h1","type":"paragraph","text":"Добывается из **Медной руды** при переработке в **переработчике**."},{"id":"h2","type":"tip","icon":"Применение","text":"Используется в кастомном крафте."}]' WHERE id = 15;

UPDATE articles SET content = '[{"id":"i1","type":"paragraph","text":"После обновления **Металлолом** больше не единственный способ продвигаться по крафту. Появились **Blueprint Fragment** (Фрагменты чертежей) — продвинутые и базовые."},{"id":"i2","type":"tip","icon":"Где получить","text":"Выбивается из убийства игроков и зомби, а также из ящиков на карте. Хранится в инвентаре и используется для разблокировки чертежей."}]' WHERE id = 16;
